                        <?php
                        $data = Rating::where('pid', $item->id)->where('status', 1)->sum('rate');
                        $count = Rating::where(['pid' => $item->id])
                            ->where('status', 1)
                            ->count();
                        if ($count && $data) {
                            $rate = $data / $count;
                        } else {
                            $rate = 0;
                        }
                        ?>
                        <div class="stars rating_stars">
                            @for ($i = 1; $i <= 5; $i++)
                                @if ($rate >= $i)
                                    <i class="fa fa-star checked"></i>
                                @elseif ($rate > $i - 1)
                                    <i class="fa fa-star-half-o checked" style="font-size: 16px;font-weight: bolder;"></i>
                                @else
                                    <i class="fa fa-star"></i>
                                @endif
                            @endfor
                            <span>({{ number_format($rate, 2) }}/5.00)</span>
                        </div>

                        <p>
                            <?php
                            $discount_price = $item->discount_price;
                            $selling_price = $item->selling_price;
                            if ($selling_price > 0) {
                                $discount_percentage = round((($selling_price - $discount_price) / $selling_price) * 100);
                            } else {
                                $discount_percentage = 0;
                            }
                            ?>
                            <span class="icon-aed">{{ getSetting('currency') }}</span>
                            <span>{{ $item->discount_price }}</span> &nbsp;
                            @if ($selling_price > 0)
                                <del><span class="icon-aed">{{ getSetting('currency') }}</span>
                                    <span>{{ $item->selling_price }}</span></del> &nbsp;
                                <span>{{ $discount_percentage }}% Off</span>
                            @endif
                        </p>
